import { useState, useEffect } from 'react';
import API from '../../services/axios';

function AllBookings() {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const res = await API.get('/bookings/all/bookings');
        setBookings(res.data.bookings || []);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    fetchBookings();
  }, []);

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
      <p style={{ color: '#6b7280' }}>Loading bookings...</p>
    </div>
  );

  return (
    <div style={{ padding: '2rem', background: '#f8f7ff', minHeight: '100vh' }}>
      <div style={{ marginBottom: '1.5rem' }}>
        <h1 style={{ fontSize: '1.5rem', fontWeight: '800', color: '#1e1b4b' }}>All Bookings</h1>
        <p style={{ color: '#6b7280', fontSize: '0.85rem' }}>{bookings.length} total bookings</p>
      </div>

      <div style={{ background: 'white', borderRadius: '16px', boxShadow: '0 2px 10px rgba(0,0,0,0.06)', overflow: 'hidden' }}>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.85rem' }}>
            <thead>
              <tr style={{ background: 'linear-gradient(135deg, #1e1b4b, #312e81)' }}>
                {['USER', 'EMAIL', 'EVENT', 'SEATS', 'AMOUNT', 'BOOKING STATUS'].map(h => (
                  <th key={h} style={{ padding: '14px 16px', textAlign: 'left', color: 'rgba(255,255,255,0.8)', fontWeight: '600', fontSize: '0.72rem', letterSpacing: '1px' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {bookings.length === 0 ? (
                <tr>
                  <td colSpan={6} style={{ padding: '3rem', textAlign: 'center', color: '#9ca3af' }}>
                    <div style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>📦</div>
                    No bookings found
                  </td>
                </tr>
              ) : bookings.map((booking, i) => (
                <tr key={booking._id} style={{ borderBottom: '1px solid #f3f4f6', background: i % 2 === 0 ? 'white' : '#fafafa' }}>
                  <td style={{ padding: '14px 16px', fontWeight: '600', color: '#1f2937' }}>{booking.user?.name}</td>
                  <td style={{ padding: '14px 16px', color: '#6b7280' }}>{booking.user?.email}</td>
                  <td style={{ padding: '14px 16px', color: '#4b5563' }}>{booking.event?.name}</td>
                  <td style={{ padding: '14px 16px', color: '#4b5563', textAlign: 'center' }}>{booking.numberOfTickets}</td>
                  <td style={{ padding: '14px 16px', fontWeight: '700', color: '#7c3aed' }}>₹{booking.totalAmount}</td>
                  <td style={{ padding: '14px 16px' }}>
                    <span style={{
                      padding: '5px 12px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: '600',
                      background: booking.status === 'confirmed' ? '#d1fae5' : booking.status === 'pending' ? '#fef3c7' : '#fee2e2',
                      color: booking.status === 'confirmed' ? '#065f46' : booking.status === 'pending' ? '#92400e' : '#991b1b'
                    }}>{booking.status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
export default AllBookings;
